import { useEffect, useState } from "react";
import PageHeader from "../components/PageHeader";
import { getAdminAlerts } from "../services/api";

export default function AdminAlertsPage() {
  const [alerts, setAlerts] = useState([]);

  useEffect(() => {
    const load = async () => setAlerts(await getAdminAlerts());
    load();
  }, []);

  return (
    <>
      <PageHeader title="Emergency Alerts" description="Dedicated critical-case monitoring with strong visual emphasis for urgent interventions." />
      <div className="card-grid">
        {alerts.map((alert) => (
          <div key={alert.id} className="metric-card alert-card">
            <span className="pill pill-danger">Immediate Attention Required</span>
            <strong style={{ fontSize: "1.1rem" }}>{alert.user.name}</strong>
            <div>{alert.message}</div>
            <div className="muted">{new Date(alert.created_at).toLocaleString()}</div>
          </div>
        ))}
      </div>
    </>
  );
}
